const DB = {
  get(k){try{return JSON.parse(localStorage.getItem("eb_"+k))||[]}catch{return[]}},
  set(k,v){localStorage.setItem("eb_"+k,JSON.stringify(v))},
  getOne(k){try{return JSON.parse(localStorage.getItem("eb_"+k))}catch{return null}},
  setOne(k,v){localStorage.setItem("eb_"+k,JSON.stringify(v))}
};

function genId(pfx){
  const k="eb_ctr_"+pfx;
  const n=(parseInt(localStorage.getItem(k)||"0"))+1;
  localStorage.setItem(k,n);
  return pfx+String(n).padStart(4,"0");
}

