// ═══════ UTILS ═══════
const fmt = n => "Rp "+Number(n||0).toLocaleString("id-ID");
const fmtDate = d => {try{return new Date(d+"T12:00:00").toLocaleDateString("id-ID",{day:"numeric",month:"short",year:"numeric"})}catch{return d}};
const today = () => new Date().toISOString().slice(0,10);
const el = id => document.getElementById(id);
const esc = s => String(s||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");

function toast(title,msg="",type="success"){
  const ic={success:"✅",error:"❌",warn:"⚠️",info:"ℹ️"};
  const d=document.createElement("div");
  d.className="toast t-"+type;
  d.innerHTML=`<div class="toast-ico">${ic[type]||"✅"}</div><div><div class="toast-title">${esc(title)}</div>${msg?`<div class="toast-msg">${esc(msg)}</div>`:""}</div>`;
  el("toast-area").prepend(d);
  setTimeout(()=>{d.style.opacity="0";d.style.transform="translateX(100%)";d.style.transition="all .3s";setTimeout(()=>d.remove(),300)},3500);
}
function modal(title,body,footer="",lg=false,sm=false){
  el("modal-title").textContent=title;
  el("modal-body").innerHTML=body;
  el("modal-footer").innerHTML=footer||`<button class="btn btn-secondary" onclick="closeModal()">Tutup</button>`;
  el("modal-box").className="modal-box"+(lg?" lg":sm?" sm":"");
  el("modal-overlay").classList.add("open");
}
function closeModal(){el("modal-overlay").classList.remove("open")}
function overlayClose(e){if(e.target===el("modal-overlay"))closeModal()}
function confirm_(title,msg,onYes,danger=false){
  modal(title,`<div class="confirm-emoji">${danger?"🗑️":"❓"}</div><div class="confirm-text">${msg}</div>`,
    `<button class="btn btn-secondary" onclick="closeModal()">Batal</button>
     <button class="btn ${danger?"btn-danger":"btn-primary"}" onclick="closeModal();(${onYes.toString()})()">Ya, Lanjutkan</button>`,
    false,true);
}
function setBtn(id,loading,lbl=""){
  const b=el(id);if(!b)return;
  b.disabled=loading;
  b.innerHTML=loading?`<span style="animation:spin .7s linear infinite;display:inline-block">⟳</span>`:lbl;
}
function pageLoader(){return`<div class="page-loader"><div class="spinner"></div><span>Memuat...</span></div>`}
function barChart(data,kv,kl,mh=100){
  if(!data||!data.length)return`<p style="color:var(--ink4);text-align:center;padding:24px">Belum ada data</p>`;
  const mx=Math.max(...data.map(d=>d[kv]||0),1);
  return`<div class="bar-chart">${data.map(d=>`<div class="bar-item"><div class="bar-fill" style="height:${Math.max(Math.round((d[kv]||0)/mx*mh),3)}px"><div class="bar-tip">${fmt(d[kv])}</div></div><div class="bar-lbl">${esc(String(d[kl]||"").slice(-5))}</div></div>`).join("")}</div>`;
}
function stokBadge(s){
  if(s>=20)return`<span class="badge b-green">${s}</span>`;
  if(s>=10)return`<span class="badge b-yellow">${s}</span>`;
  return`<span class="badge b-red">${s}</span>`;
}
function statusBadge(s){
  const map={menunggu:"b-yellow",diproses:"b-blue",selesai:"b-green",dibatalkan:"b-red"};
  return`<span class="badge ${map[s]||"b-gray"}">${s}</span>`;
}
function openSb(){el("sidebar").classList.add("open");el("sb-overlay").classList.add("open")}
function closeSb(){el("sidebar").classList.remove("open");el("sb-overlay").classList.remove("open")}

// ═══════ AUTH ═══════
let _role="admin", _user=null;

function setRole(r){
  _role=r;
  document.querySelectorAll(".role-tab").forEach(b=>b.classList.toggle("active",b.onclick.toString().includes(`'${r}'`)));
  const demos={admin:"admin / admin123",nasabah:"siti / siti123",pemasok:"pemasok1 / pasok123"};
  el("demo-cred").textContent=demos[r]||"";
  el("reg-link").style.display=r==="nasabah"?"block":"none";
  el("demo-hint").style.display=r==="reg"?"none":"block";
}
function showReg(){el("lf-login").classList.remove("active");el("lf-reg").classList.add("active");el("demo-hint").style.display="none"}
function showLogin(){el("lf-reg").classList.remove("active");el("lf-login").classList.add("active");el("demo-hint").style.display="block"}

function doLogin(){
  const u=el("f-user").value.trim(),p=el("f-pass").value.trim();
  el("login-err").textContent="";
  if(!u||!p){el("login-err").textContent="⚠ Username & password wajib diisi";return}
  setBtn("btn-login",true);
  setTimeout(()=>{
    const users=DB.get("users");
    const found=users.find(x=>x.username===u&&x.password===p&&x.role===_role);
    if(!found){el("login-err").textContent="⚠ Username atau password salah";setBtn("btn-login",false,"Masuk →");return}
    _user=found;DB.setOne("session",found.id);
    el("login-screen").style.display="none";
    el("app").classList.add("show");
    initApp();
    toast("Selamat datang, "+found.name+"! 👋");
    setBtn("btn-login",false,"Masuk →");
  },350);
}

function doReg(){
  const nama=el("r-nama").value.trim(),user=el("r-user").value.trim(),
        pass=el("r-pass").value.trim(),hp=el("r-hp").value.trim(),alamat=el("r-alamat").value.trim();
  el("reg-err").textContent="";
  if(!nama||!user||!pass||!hp||!alamat){el("reg-err").textContent="⚠ Semua field wajib diisi";return}
  if(pass.length<6){el("reg-err").textContent="⚠ Password min 6 karakter";return}
  const users=DB.get("users");
  if(users.find(u=>u.username===user)){el("reg-err").textContent="⚠ Username sudah dipakai";return}
  setBtn("btn-reg",true);
  setTimeout(()=>{
    const nid=genId("N"),uid=genId("U");
    DB.set("nasabah",[...DB.get("nasabah"),{id:nid,nama,alamat,no_hp:hp,saldo:0,created_at:today()}]);
    DB.set("users",[...users,{id:uid,username:user,password:pass,role:"nasabah",name:nama,ref_id:nid}]);
    toast("Registrasi berhasil!","Silakan login");
    el("r-nama").value=el("r-user").value=el("r-pass").value=el("r-hp").value=el("r-alamat").value="";
    showLogin();el("f-user").value=user;setRole("nasabah");
    setBtn("btn-reg",false,"🌱 Daftar Sekarang");
  },400);
}

function doLogout(){
  confirm_("Keluar?","Yakin ingin keluar?",()=>{
    _user=null;DB.setOne("session",null);
    el("app").classList.remove("show");
    el("login-screen").style.display="flex";
    el("f-user").value="";el("f-pass").value="";
  });
}

