let _view="";

function initApp(){
  document.querySelectorAll("[data-logo]").forEach(i=>i.src=LOGO);
  el("sb-logo").src=LOGO;el("login-logo").src=LOGO;
  const u=_user;
  el("sb-ava").textContent={admin:"🛡️",nasabah:"🙋",pemasok:"🏪"}[u.role]||"👤";
  el("tb-ava").textContent={admin:"🛡️",nasabah:"🙋",pemasok:"🏪"}[u.role]||"👤";
  el("sb-uname").textContent=u.name;
  el("sb-urole").textContent={admin:"Administrator",nasabah:"Nasabah",pemasok:"Pemasok Sembako"}[u.role];
  el("sb-badge").textContent=u.role.toUpperCase();
  el("sb-badge").className="sb-badge "+u.role;
  el("tb-name").textContent=u.name;
  buildNav(u.role);
  const def={admin:"a-dash",nasabah:"n-dash",pemasok:"p-dash"};
  nav(def[u.role]);
}

function buildNav(role){
  const items=MENUS[role]||[];
  el("sb-nav").innerHTML=items.map(m=>{
    if(m.sec)return`<div class="nav-sec">${m.sec}</div>`;
    return`<button class="nav-item" id="ni-${m.id}" onclick="nav('${m.id}')"><span class="nav-ico">${m.ico}</span>${esc(m.lbl)}</button>`;
  }).join("");
}

async function nav(vid){
  _view=vid;
  document.querySelectorAll(".nav-item").forEach(b=>b.classList.remove("active"));
  const ni=el("ni-"+vid);if(ni)ni.classList.add("active");
  const allItems=Object.values(MENUS).flat().filter(m=>m.id);
  const item=allItems.find(m=>m.id===vid);
  if(item){el("tb-ico").textContent=item.ico;el("tb-title").textContent=item.lbl}
  el("page").innerHTML=pageLoader();
  closeSb();
  const views={
    "a-dash":vAdminDash,"a-nasabah":vAdminNasabah,"a-jenis":vAdminJenis,
    "a-setoran":vAdminSetoran,"a-penarikan":vAdminPenarikan,
    "a-penukaran":vAdminPenukaran,"a-sembako":vAdminSembako,
    "a-pemasok":vAdminPemasok,"a-laporan":vAdminLaporan,
    "n-dash":vNasabahDash,"n-setoran":vNasabahSetoran,"n-cash":vNasabahCash,
    "n-sembako":vNasabahSembako,"n-riwayat":vNasabahRiwayat,
    "n-harga":vNasabahHarga,"n-katalog":vNasabahKatalog,"n-profil":vNasabahProfil,
    "p-dash":vPemasokDash,"p-sembako":vPemasokSembako,"p-penukaran":vPemasokPenukaran,
  };
  try{
    await new Promise(r=>setTimeout(r,50));
    if(views[vid])await views[vid]();
    else el("page").innerHTML=`<div class="empty-state"><div class="empty-ico">🚧</div><h3>Halaman belum tersedia</h3></div>`;
  }catch(e){
    el("page").innerHTML=`<div class="empty-state"><div class="empty-ico">⚠️</div><h3>Error</h3><p>${esc(e.message)}</p><button class="btn btn-secondary" style="margin-top:14px" onclick="nav('${vid}')">🔄 Coba lagi</button></div>`;
  }
}

