        penarikan=DB.get("penarikan"),penukaran=DB.get("penukaran"),
        sembako=DB.get("sembako");
  const totalSaldo=nasabah.reduce((s,n)=>s+n.saldo,0);
  const totalBerat=setoran.reduce((s,t)=>s+t.berat,0);
  const totalNilai=setoran.reduce((s,t)=>s+t.total,0);
  const stokRendah=sembako.filter(s=>s.stok<10).length;
  const pending=penukaran.filter(p=>p.status==="menunggu").length;
