function updateSembako(id){
  DB.set("sembako",DB.get("sembako").map(s=>s.id===id?{...s,
    nama_barang:el("es-nama").value.trim(),harga:parseFloat(el("es-harga").value)||0,
    stok:parseFloat(el("es-stok").value)||0,satuan:el("es-satuan").value,
    icon:el("es-icon").value,pemasok_id:el("es-pms").value}:s));
  closeModal();toast("Sembako diperbarui");vAdminSembako();
}
