function vNasabahCash(){
  const n=getNasabahData();
  const recent=DB.get("penarikan").filter(p=>p.nasabah_id===n.id).sort((a,b)=>b.tanggal.localeCompare(a.tanggal));
  el("page").innerHTML=`
  <div class="page-header"><h2>Tarik Tunai</h2><p>Tarik saldo tabungan dalam bentuk cash</p></div>
  <div class="two-col">
    <div>
      <div class="saldo-hero" style="margin-bottom:16px">
        <div class="saldo-lbl">Saldo Tersedia</div>
        <div class="saldo-amt">${fmt(n.saldo)}</div>
      </div>
      <div class="card">
        <div class="card-header"><div class="card-title">💵 Form Penarikan Tunai</div></div>
        <div class="card-body">
          <div class="form-group"><label>Tanggal</label><input type="date" id="nc-tgl" class="form-control" value="${today()}"></div>
          <div class="form-group"><label>Jumlah (Rp)</label>
            <input type="number" id="nc-jml" class="form-control" placeholder="0" min="1000" step="1000" max="${n.saldo}"></div>
          <div class="form-hint">Maksimal: ${fmt(n.saldo)}</div>
          <div class="form-error" id="nc-err" style="margin-top:8px"></div>
          <button class="btn btn-primary btn-full btn-lg" id="btn-nc" onclick="simpanTarikCash(${n.saldo})" style="margin-top:12px">💵 Tarik Tunai</button>
        </div>
      </div>
    </div>
    <div class="card">
      <div class="card-header"><div class="card-title">📋 Riwayat Tarik Tunai</div></div>
      <div class="table-wrap"><table>
        <thead><tr><th>Tanggal</th><th>Jumlah</th></tr></thead>
        <tbody>
          ${recent.length?recent.map(p=>`<tr><td>${fmtDate(p.tanggal)}</td><td><span class="badge b-blue">${fmt(p.jumlah)}</span></td></tr>`).join(""):`<tr><td colspan="2"><div class="empty-state" style="padding:20px"><p>Belum ada penarikan</p></div></td></tr>`}
        </tbody>
      </table></div>
    </div>
  </div>`;
}
function simpanTarikCash(maxSaldo){
  const tgl=el("nc-tgl").value,jml=parseFloat(el("nc-jml").value)||0;
  const e=el("nc-err");e.textContent="";
  if(!tgl||jml<1000){e.textContent="⚠ Isi semua, minimal Rp 1.000";return}
  if(jml>maxSaldo){e.textContent=`⚠ Melebihi saldo (${fmt(maxSaldo)})`;return}
  const n=getNasabahData();
  const id=genId("TAR");
  DB.set("penarikan",[...DB.get("penarikan"),{id,tanggal:tgl,nasabah_id:n.id,metode:"cash",jumlah:jml}]);
  DB.set("nasabah",DB.get("nasabah").map(x=>x.id===n.id?{...x,saldo:x.saldo-jml}:x));
  toast("Penarikan berhasil!",`-${fmt(jml)}`);vNasabahCash();
}

function vNasabahSembako(){
  const n=getNasabahData();
  const sembako=DB.get("sembako");
  let _nk={};
  el("page").innerHTML=`
  <div class="page-header"><h2>Tukar Sembako</h2><p>Tukarkan saldo dengan produk sembako pilihan</p></div>
  <div class="saldo-hero" style="margin-bottom:16px">
    <div class="saldo-lbl">Saldo Tersedia</div>
    <div class="saldo-amt">${fmt(n.saldo)}</div>
  </div>
  <div class="two-col-rev">
    <div class="card">
      <div class="card-header"><div class="card-title">🌾 Pilih Produk</div></div>
      <div style="padding:13px">
        <div class="smb-grid" id="nsmb-picker">
          ${sembako.map(s=>`
          <div class="smb-card ${s.stok<=0?"oos":""}" id="nsc-${s.id}" onclick="nToggle('${s.id}',${s.harga},${s.stok},'${esc(s.nama_barang)}')">
            <div class="smb-check">✓</div>
            <div class="smb-ico">${s.icon||"📦"}</div>
            <div class="smb-name">${esc(s.nama_barang)}</div>
            <div class="smb-price">${fmt(s.harga)}<span style="font-size:10px;font-weight:400;color:var(--ink3)">/${s.satuan}</span></div>
            <div class="smb-stok">Stok: ${s.stok} ${s.satuan}</div>
            <div class="stok-bar"><div class="stok-fill ${s.stok>=20?"hi":s.stok>=10?"mid":"lo"}" style="width:${Math.min(s.stok/50*100,100)}%"></div></div>
            <div class="smb-qty">
              <button class="qty-btn" onclick="event.stopPropagation();nAdj('${s.id}',-1,${s.harga},${s.stok})">−</button>
              <span class="qty-val" id="nq-${s.id}">1</span>
              <button class="qty-btn" onclick="event.stopPropagation();nAdj('${s.id}',1,${s.harga},${s.stok})">+</button>
            </div>
          </div>`).join("")}
        </div>
      </div>
    </div>
    <div>
      <div class="card" style="position:sticky;top:80px">
        <div class="card-header"><div class="card-title">🧾 Keranjang</div></div>
        <div class="card-body" id="nk-body"><div class="empty-state" style="padding:20px"><div class="empty-ico" style="font-size:28px">🛒</div><p>Pilih produk</p></div></div>
        <div class="card-footer">
          <div class="form-error" id="ns-err" style="margin-bottom:8px"></div>
          <button class="btn btn-primary btn-full btn-lg" onclick="simpanTukar(${n.saldo})">✅ Tukar Sekarang</button>
        </div>
      </div>
    </div>
  </div>`;
  window._nk={};
}
function nToggle(id,harga,stok,nama){
  if(stok<=0)return;
  if(window._nk[id]){delete window._nk[id];el("nsc-"+id).classList.remove("sel");}
  else{window._nk[id]={id,harga,stok,nama,qty:1};el("nsc-"+id).classList.add("sel");}
  nRenderK();
}
function nAdj(id,d,harga,stok){
  if(!window._nk[id])return;
  window._nk[id].qty=Math.max(1,Math.min(stok,(window._nk[id].qty||1)+d));
  el("nq-"+id).textContent=window._nk[id].qty;nRenderK();
}
function nRenderK(){
  const items=Object.values(window._nk||{});
  if(!items.length){el("nk-body").innerHTML=`<div class="empty-state" style="padding:20px"><div class="empty-ico" style="font-size:28px">🛒</div><p>Pilih produk</p></div>`;return}
  const total=items.reduce((s,i)=>s+i.qty*i.harga,0);
  el("nk-body").innerHTML=`
    ${items.map(i=>`<div class="k-item"><div><div style="font-weight:700;font-size:13px">${esc(i.nama)}</div><div style="font-size:11px;color:var(--ink4)">${i.qty} × ${fmt(i.harga)}</div></div><strong style="color:var(--g700)">${fmt(i.qty*i.harga)}</strong></div>`).join("")}
    <div class="k-total"><span class="k-total-lbl">Total</span><span class="k-total-val">${fmt(total)}</span></div>`;
}
function simpanTukar(maxSaldo){
  const items=Object.values(window._nk||{});
  const e=el("ns-err");e.textContent="";
  if(!items.length){e.textContent="⚠ Keranjang kosong";return}
  const total=items.reduce((s,i)=>s+i.qty*i.harga,0);
  if(total>maxSaldo){e.textContent=`⚠ Saldo tidak cukup (${fmt(maxSaldo)})`;return}
  const n=getNasabahData();
  const pid=genId("PNK");
  DB.set("penukaran",[...DB.get("penukaran"),{id:pid,tanggal:today(),nasabah_id:n.id,total_harga:total,status:"menunggu"}]);
  const detail=DB.get("detail_penukaran");
  items.forEach(i=>{detail.push({id:genId("DP"),penukaran_id:pid,sembako_id:i.id,qty:i.qty,harga:i.harga,subtotal:i.qty*i.harga})});
  DB.set("detail_penukaran",detail);
  DB.set("nasabah",DB.get("nasabah").map(x=>x.id===n.id?{...x,saldo:x.saldo-total}:x));
  DB.set("sembako",DB.get("sembako").map(s=>{const item=(window._nk||{})[s.id];return item?{...s,stok:s.stok-item.qty}:s}));
  toast("Penukaran berhasil!",`-${fmt(total)} · Status: Menunggu`);nav("n-riwayat");
}

function vNasabahRiwayat(){
  const n=getNasabahData();
  const penarikan=DB.get("penarikan").filter(p=>p.nasabah_id===n.id).sort((a,b)=>b.tanggal.localeCompare(a.tanggal));
  const penukaran=DB.get("penukaran").filter(p=>p.nasabah_id===n.id).sort((a,b)=>b.tanggal.localeCompare(a.tanggal));
  const smbMap=Object.fromEntries(DB.get("sembako").map(s=>[s.id,s]));
  const dpMap={};
  DB.get("detail_penukaran").forEach(d=>{if(!dpMap[d.penukaran_id])dpMap[d.penukaran_id]=[];dpMap[d.penukaran_id].push(d)});
  el("page").innerHTML=`
  <div class="page-header"><h2>Riwayat Penarikan</h2><p>Semua penarikan dan penukaran Anda</p></div>
  <div class="tab-bar" id="rw-tabs">
    <button class="tab-btn active" onclick="showRwTab('cash')">💵 Penarikan Cash</button>
    <button class="tab-btn" onclick="showRwTab('sembako')">🛒 Penukaran Sembako</button>
  </div>
  <div id="rw-cash">
    <div class="card"><div class="table-wrap"><table>
      <thead><tr><th>Tanggal</th><th>Jumlah</th></tr></thead>
      <tbody>
        ${penarikan.length?penarikan.map(p=>`<tr><td>${fmtDate(p.tanggal)}</td><td><span class="badge b-blue">${fmt(p.jumlah)}</span></td></tr>`).join(""):`<tr><td colspan="2"><div class="empty-state" style="padding:24px"><div class="empty-ico">💸</div><h3>Belum ada penarikan</h3></div></td></tr>`}
      </tbody>
    </table></div></div>
  </div>
  <div id="rw-sembako" style="display:none">
    <div class="card"><div class="table-wrap"><table>
      <thead><tr><th>Tanggal</th><th>Produk</th><th>Total</th><th>Status</th></tr></thead>
      <tbody>
        ${penukaran.length?penukaran.map(p=>{
          const details=(dpMap[p.id]||[]).map(d=>`${smbMap[d.sembako_id]?.icon||"📦"} ${d.qty}x ${esc(smbMap[d.sembako_id]?.nama_barang||"?")}`).join(", ");
          return`<tr>
            <td>${fmtDate(p.tanggal)}</td>
            <td style="font-size:12px">${details||"-"}</td>
            <td><strong style="color:var(--g700)">${fmt(p.total_harga)}</strong></td>
            <td>${statusBadge(p.status)}</td>
          </tr>`}).join(""):`<tr><td colspan="4"><div class="empty-state" style="padding:24px"><div class="empty-ico">🛒</div><h3>Belum ada penukaran</h3></div></td></tr>`}
      </tbody>
    </table></div></div>
  </div>`;
}
function showRwTab(t){
  el("rw-cash").style.display=t==="cash"?"block":"none";
  el("rw-sembako").style.display=t==="sembako"?"block":"none";
  document.querySelectorAll("#rw-tabs .tab-btn").forEach((b,i)=>b.classList.toggle("active",(i===0&&t==="cash")||(i===1&&t==="sembako")));
}

