// PEMASOK VIEWS
// ═══════════════════════════════════════════════════════════
function getPemasokData(){
  return DB.get("pemasok").find(p=>p.id===_user.ref_id)||{id:_user.ref_id,nama:_user.name};
}

function vPemasokDash(){
  const p=getPemasokData();
  const sembako=DB.get("sembako").filter(s=>s.pemasok_id===p.id);
  const nilaiStok=sembako.reduce((s,x)=>s+x.harga*x.stok,0);
  const rendah=sembako.filter(s=>s.stok<10).length;
  const allPnk=DB.get("penukaran");
  const allDp=DB.get("detail_penukaran");
  const myIds=new Set(sembako.map(s=>s.id));
  const relPnk=allPnk.filter(pnk=>allDp.some(d=>d.penukaran_id===pnk.id&&myIds.has(d.sembako_id)));
  const pending=relPnk.filter(p=>p.status==="menunggu").length;
  el("page").innerHTML=`
  <div class="page-header"><h2>Dashboard Pemasok</h2><p>Selamat datang, ${esc(p.nama)}!</p></div>
  <div class="stat-grid">
    <div class="stat-card"><div class="stat-bg">🌾</div><div class="stat-ico">🌾</div>
      <div class="stat-label">Total Produk</div><div class="stat-val">${sembako.length}</div>
    </div>
    <div class="stat-card"><div class="stat-bg">💰</div><div class="stat-ico">💰</div>
      <div class="stat-label">Nilai Stok</div><div class="stat-val" style="font-size:16px">${fmt(nilaiStok)}</div>
    </div>
    ${rendah>0?`<div class="stat-card"><div class="stat-bg">⚠️</div><div class="stat-ico">⚠️</div>
      <div class="stat-label">Stok Rendah</div><div class="stat-val">${rendah}</div>
      <span class="stat-tag danger">Perlu restok</span>
    </div>`:""}
    ${pending>0?`<div class="stat-card" onclick="nav('p-penukaran')" style="cursor:pointer"><div class="stat-bg">⏳</div><div class="stat-ico">⏳</div>
      <div class="stat-label">Permintaan Pending</div><div class="stat-val">${pending}</div>
      <span class="stat-tag warn">Perlu tindakan</span>
    </div>`:""}
  </div>
  <div class="card">
    <div class="card-header">
      <div class="card-title">🌾 Produk Saya</div>
      <button class="btn btn-ghost btn-sm" onclick="nav('p-sembako')">Kelola →</button>
    </div>
    <div class="table-wrap"><table>
      <thead><tr><th>Produk</th><th>Harga</th><th>Stok</th><th>Status</th></tr></thead>
      <tbody>
        ${sembako.map(s=>`<tr>
          <td><strong>${s.icon||"📦"} ${esc(s.nama_barang)}</strong></td>
          <td>${fmt(s.harga)}/${s.satuan}</td>
          <td>${stokBadge(s.stok)} ${s.satuan}</td>
          <td>${s.stok<=0?`<span class="badge b-red">Habis</span>`:s.stok<10?`<span class="badge b-yellow">Rendah</span>`:`<span class="badge b-green">Tersedia</span>`}</td>
        </tr>`).join("")}
      </tbody>
    </table></div>
  </div>`;
}

function vPemasokSembako(){
  const p=getPemasokData();
  const sembako=DB.get("sembako").filter(s=>s.pemasok_id===p.id);
  el("page").innerHTML=`
  <div class="page-row">
    <div class="page-header"><h2>Kelola Sembako</h2><p>Produk milik ${esc(p.nama)}</p></div>
    <button class="btn btn-primary" onclick="mTambahSmbPms()">➕ Tambah Produk</button>
  </div>
  <div class="card"><div class="table-wrap"><table>
    <thead><tr><th>Produk</th><th>Harga</th><th>Stok</th><th>Aksi</th></tr></thead>
    <tbody>
      ${sembako.length?sembako.map(s=>`<tr>
        <td><strong>${s.icon||"📦"} ${esc(s.nama_barang)}</strong></td>
        <td>${fmt(s.harga)}/${s.satuan}</td>
        <td>${stokBadge(s.stok)} ${s.satuan}</td>
        <td><div class="td-actions">
          <button class="btn btn-xs btn-secondary" onclick="mRestokPms('${s.id}','${esc(s.nama_barang)}',${s.stok})">📦 Restok</button>
          <button class="btn btn-xs btn-secondary" onclick='mEditSmbPms(${JSON.stringify(s)})'>✏️ Edit</button>
        </div></td>
      </tr>`).join(""):`<tr><td colspan="4"><div class="empty-state" style="padding:28px"><div class="empty-ico">🌾</div><h3>Belum ada produk</h3></div></td></tr>`}
    </tbody>
  </table></div></div>`;
}
function mTambahSmbPms(){
  modal("➕ Tambah Produk",`
    <div class="form-row">
      <div class="form-group"><label>Nama Produk</label><input id="pt-nama" class="form-control"></div>
      <div class="form-group"><label>Icon</label>
        <select id="pt-icon" class="form-control">${ICONS.map(i=>`<option value="${i}">${i}</option>`).join("")}</select></div>
    </div>
    <div class="form-row">
      <div class="form-group"><label>Harga (Rp)</label><input id="pt-harga" type="number" class="form-control" placeholder="0"></div>
      <div class="form-group"><label>Stok Awal</label><input id="pt-stok" type="number" class="form-control" placeholder="0"></div>
    </div>
    <div class="form-group"><label>Satuan</label>
      <select id="pt-satuan" class="form-control">${["kg","liter","pcs","butir","bungkus","botol"].map(s=>`<option>${s}</option>`).join("")}</select></div>
    <div class="form-error" id="pt-err"></div>`,
    `<button class="btn btn-secondary" onclick="closeModal()">Batal</button>
     <button class="btn btn-primary" onclick="simpanSmbPms()">💾 Simpan</button>`);
}
function simpanSmbPms(){
  const nama=el("pt-nama").value.trim(),harga=parseFloat(el("pt-harga").value)||0;
  if(!nama||!harga){el("pt-err").textContent="⚠ Nama & harga wajib";return}
  const p=getPemasokData();
  const id=genId("SMB");
  DB.set("sembako",[...DB.get("sembako"),{id,nama_barang:nama,harga,stok:parseFloat(el("pt-stok").value)||0,satuan:el("pt-satuan").value,icon:el("pt-icon").value,pemasok_id:p.id}]);
  closeModal();toast("Produk ditambahkan");vPemasokSembako();
}
function mEditSmbPms(s){
  modal("✏️ Edit Produk",`
    <div class="form-row">
      <div class="form-group"><label>Nama</label><input id="pe-nama" class="form-control" value="${esc(s.nama_barang)}"></div>
      <div class="form-group"><label>Icon</label>
        <select id="pe-icon" class="form-control">${ICONS.map(i=>`<option value="${i}" ${i===s.icon?"selected":""}>${i}</option>`).join("")}</select></div>
    </div>
    <div class="form-row">
      <div class="form-group"><label>Harga (Rp)</label><input id="pe-harga" type="number" class="form-control" value="${s.harga}"></div>
      <div class="form-group"><label>Satuan</label>
        <select id="pe-satuan" class="form-control">${["kg","liter","pcs","butir","bungkus","botol"].map(u=>`<option ${u===s.satuan?"selected":""}>${u}</option>`).join("")}</select></div>
    </div>`,
    `<button class="btn btn-secondary" onclick="closeModal()">Batal</button>
     <button class="btn btn-primary" onclick="updateSmbPms('${s.id}')">💾 Simpan</button>`);
}
function updateSmbPms(id){
  DB.set("sembako",DB.get("sembako").map(s=>s.id===id?{...s,nama_barang:el("pe-nama").value.trim(),harga:parseFloat(el("pe-harga").value)||0,satuan:el("pe-satuan").value,icon:el("pe-icon").value}:s));
  closeModal();toast("Produk diperbarui");vPemasokSembako();
}
function mRestokPms(id,nama,stok){
  modal("📦 Restok",`
    <div style="text-align:center;margin-bottom:12px"><div style="font-size:26px">📦</div>
    <div style="font-weight:700">${esc(nama)}</div><div style="color:var(--ink3);font-size:13px">Stok: ${stok}</div></div>
    <div class="form-group"><label>Tambah Stok</label><input id="rp-jml" type="number" class="form-control" placeholder="0" min="1"></div>
    <div class="form-error" id="rp-err"></div>`,
    `<button class="btn btn-secondary" onclick="closeModal()">Batal</button>
     <button class="btn btn-primary" onclick="simpanRestokPms('${id}')">📦 Tambah</button>`,false,true);
}
function simpanRestokPms(id){
  const jml=parseFloat(el("rp-jml").value)||0;
  if(jml<=0){el("rp-err").textContent="⚠ Masukkan jumlah";return}
  DB.set("sembako",DB.get("sembako").map(s=>s.id===id?{...s,stok:s.stok+jml}:s));
  closeModal();toast("Restok berhasil!",`+${jml}`);vPemasokSembako();
}

function vPemasokPenukaran(){
  const p=getPemasokData();
  const sembako=DB.get("sembako").filter(s=>s.pemasok_id===p.id);
  const myIds=new Set(sembako.map(s=>s.id));
  const allDp=DB.get("detail_penukaran");
  const allPnk=DB.get("penukaran");
  const nMap=Object.fromEntries(DB.get("nasabah").map(n=>[n.id,n]));
  const smbMap=Object.fromEntries(DB.get("sembako").map(s=>[s.id,s]));
  const dpMap={};
  allDp.forEach(d=>{if(!dpMap[d.penukaran_id])dpMap[d.penukaran_id]=[];dpMap[d.penukaran_id].push(d)});
  const relPnk=allPnk.filter(pnk=>allDp.some(d=>d.penukaran_id===pnk.id&&myIds.has(d.sembako_id))).sort((a,b)=>b.tanggal.localeCompare(a.tanggal));
  el("page").innerHTML=`
  <div class="page-header"><h2>Permintaan Sembako</h2><p>Penukaran yang melibatkan produk Anda</p></div>
  <div class="card"><div class="table-wrap"><table>
    <thead><tr><th>Tanggal</th><th>Nasabah</th><th>Produk Saya</th><th>Total</th><th>Status</th><th>Aksi</th></tr></thead>
    <tbody>
      ${relPnk.length?relPnk.map(pnk=>{
        const myDetails=(dpMap[pnk.id]||[]).filter(d=>myIds.has(d.sembako_id));
        const produk=myDetails.map(d=>`${smbMap[d.sembako_id]?.icon||"📦"} ${d.qty}x ${esc(smbMap[d.sembako_id]?.nama_barang||"?")}`).join(", ");
        return`<tr>
          <td style="font-size:12.5px">${fmtDate(pnk.tanggal)}</td>
          <td><strong>${esc(nMap[pnk.nasabah_id]?.nama||"?")}</strong></td>
          <td style="font-size:12.5px">${produk}</td>
          <td><strong style="color:var(--g700)">${fmt(pnk.total_harga)}</strong></td>
          <td>${statusBadge(pnk.status)}</td>
          <td><div class="td-actions">
            ${pnk.status==="menunggu"?`<button class="btn btn-xs btn-primary" onclick="pmsSetStatus('${pnk.id}','diproses')">▶ Proses</button>`:""}
            ${pnk.status==="diproses"?`<button class="btn btn-xs btn-primary" onclick="pmsSetStatus('${pnk.id}','selesai')">✅ Selesai</button>`:""}
          </div></td>
        </tr>`}).join(""):`<tr><td colspan="6"><div class="empty-state" style="padding:28px"><div class="empty-ico">📋</div><h3>Belum ada permintaan</h3></div></td></tr>`}
    </tbody>
  </table></div></div>`;
}
function pmsSetStatus(id,status){
  DB.set("penukaran",DB.get("penukaran").map(p=>p.id===id?{...p,status}:p));
  toast("Status diperbarui",`→ ${status}`);vPemasokPenukaran();
}

// ═══════ INIT ═══════
document.addEventListener("DOMContentLoaded",()=>{
  seed();
  // Set logos
  el("login-logo").src=LOGO;
  // Restore session
  const sid=DB.getOne("session");
  if(sid){
    const users=DB.get("users");
    const u=users.find(x=>x.id===sid);
    if(u){
      _user=u;
      el("login-screen").style.display="none";
      el("app").classList.add("show");
      initApp();
      return;
    }
  }
  el("login-screen").style.display="flex";
  setRole("admin");
});
